const{readFile:readFile}=require("fs/promises"),parseJSON=require("json-parse-even-better-errors");async function read(e){try{return await readFile(e,"utf8")}catch(e){throw e.message=`Could not read package.json: ${e}`,e}}function parse(e){try{return parseJSON(e)}catch(e){throw e.message=`Invalid package.json: ${e}`,e}}async function readPackage(e){return parse(await read(e))}module.exports={read:read,parse:parse,readPackage:readPackage};